            yield return new IZELayoutItem(VanillaIZombieLayoutID.ize2Control, 1.2f); // їШЦЖ
            yield return new IZELayoutItem(VanillaIZombieLayoutID.ize2Spectral, 0.8f); // №вБйЈЁУР1»рТ©Н°Ј©

            // BАаХу
            yield return new IZELayoutItem(VanillaIZombieLayoutID.ize2Spikes, 0.4f); // ЗгР±
            yield return new IZELayoutItem(VanillaIZombieLayoutID.ize2Dispensers, 0.4f); // ·ўЙдЖчЈЁУР1»рТ©Н°Ј©
            yield return new IZELayoutItem(VanillaIZombieLayoutID.ize2Defense, 0.4f); // ·АУщ
            yield return new IZELayoutItem(VanillaIZombieLayoutID.ize2Fire, 0.4f); // »рСж
            yield return new IZELayoutItem(VanillaIZombieLayoutID.ize2Instakill, 0.2f); // јґЛА
            yield return new IZELayoutItem(VanillaIZombieLayoutID.izeAwards, 0.2f); // »Цёґ
        }
        protected override IEnumerable<IZELayoutItem> GetAwardLayouts()
        {
            yield return new IZELayoutItem(VanillaIZombieLayoutID.izeAwards);
            yield return new IZELayoutItem(VanillaIZombieLayoutID.izeError, 0.2f);
            yield return new IZELayoutItem(VanillaIZombieLayoutID.ize2Gunpowder, 0.2f);
